insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Rainforest Extension	"), TRIM("	This extension includes 3 nights at the reserve giving us a full 2 days for jungle walks and river trips. In the Tambopata Reserve we have selected two accommodations the Sandoval Lake Lodge or the Posadas Amazonas. You will be staying at either one of these lodges. Both are situated with good access and viewing points for exploring and have unique features for ensuring you see as much as possible of the rare wildlife of this pristine rainforest ecosystem. This extension starts and ends in Puerto Maldonaldo. The majority of flights here depart from Cusco. We can assist with these internal flights and any extra nights accommodation in Cusco or Lima that you may require.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0056" ), 0+1);
