insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Puno Islas del Titicaca	"), TRIM("	Visita hermosos pueblos, museos, iglesias y templos en un recorrido con paisajes impresionantes entre Cusco y Puno, durante tres incre&iacute;bles d&iacute;as. Descubre c&oacute;mo el pasado sigue vivo en las maravillosas islas del Titicaca, el lago navegable m&aacute;s alto del mundo.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0002" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Trujillo &amp; Chiclayo	"), TRIM("	Descubra Trujillo y Chiclayo en la costa norte del Per&uacute;, durante 4 d&iacute;as llenos de sol y cultura. Visita bellas iglesias y casonas de la &eacute;poca colonial, al igual que impresionantes huacas, templos y complejos arqueol&oacute;gicos que pertenecieron a civilizaciones antiguas. Recorra museos, el Valle de Chicama y disfruta los sabores marinos que ofrece el mar peruano.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0004" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Reserva Amaz&oacute;nica	"), TRIM("	Explora la selva de Puerto Maldonado y conoce su interminable fauna y flora, ya sea a trav&eacute;s de sus trochas o navegando por el r&iacute;o Madre de Dios. Descubre la gran biodiversidad de la Reserva Nacional Tambopata y observa la amazonia peruana desde la copa de los &aacute;rboles gracias a una sorprendente red de puentes colgantes.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0006" ), 0+1);
