insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	AREQUIPA &amp; CA&Ntilde;&Oacute;N DEL COLCA	"), TRIM("	Explora Arequipa, la segunda ciudad m&aacute;s grande de Per&uacute;, durante cuatro d&iacute;as de ensue&ntilde;o. Visita su estilo colonial y sus bellas iglesias, como tambi&eacute;n las pampas que hay afuera de la ciudad con espectaculares paisajes. Admira los c&oacute;ndores del Valle del Colca y a los cam&eacute;lidos aut&oacute;ctonos de los Andes. El tama&ntilde;o de los grupos es variable pero normalmente va de 6 a 10 pasajeros.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0012" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	PLAYAS DEL NORTE	"), TRIM("	Descubra las playas del norte del Per&uacute;, durante tres d&iacute;as llenos de sol y naturaleza. Disfrute del avistamiento de ballenas jorobadas en su h&aacute;bitat natural. Rel&aacute;jese contemplando el atardecer en la playa mientras disfruta de deliciosos platos a base de productos frescos del mar.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0014" ), 0+1);
