insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	PUNO ISLAS DEL TITI CACA	"), TRIM("	Disfrutar&aacute; de la naturaleza y de la relajaci&oacute;n que se transmite a trav&eacute;s del  impresionante paisaje del altiplano. Visitar&aacute; la isla de Uros y Taquile, estas  se construyen  tejiendo las totoras en los lugares en donde crece m&aacute;s tupida y formando una capa natura. Ser&aacute; un viaje que nunca olvidar&aacute;.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0053" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	AREQUIPA Y CA&Ntilde;ON DEL COLCA	"), TRIM("	Su viaje a la ciudad blanca lo dejar&aacute; deslumbrado. Visitar&aacute; la Plaza de Armas, una de las m&aacute;s bellas del Per&uacute;. El Centro Hist&oacute;rico de Arequipa, fue declarado Patrimonio Cultural de la Humanidad por la Unesco. Sin duda usted tendr&aacute; una muy grata experiencia.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0054" ), 0+1);
