insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	EXPERIENCIA CHACHAPOYAS	"), TRIM("	Descubre durante cinco emocionantes d&iacute;as los tesoros arqueol&oacute;gicos, culturales y naturales de Chachapoyas, regi&oacute;n Amazonas en la Selva Norte del Per&uacute;. Conocidos como &lsquo;Guerreros de las Nubes&rsquo;, la civilizaci&oacute;n Chachapoyas se distingue de la cultura inca por su arquitectura, cultura y costumbres. Visita la imponente Fortaleza de Ku&eacute;lap con traslado en telef&eacute;rico para conocer esta cultura poco conocida, junto con la catarata de Gocta.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0067" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	SKY LODGE	"), TRIM("	Disfruta durante dos emocionantes d&iacute;as la aventura en Valle Sagrado, regi&oacute;n sureste del Per&uacute;. La escalada de la V&iacute;a Ferrata permite una experiencia de verticalidad y el Zip line una forma divertida y segura de descender.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0068" ), 0+1);
