insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	PALCOYO MULTICOLOR	"), TRIM("	Marav&iacute;llese con Palcoyo, la nueva monta&ntilde;a de colores de Cusco. Avent&uacute;rese en una caminata por los Andes descubriendo la belleza de este destino natural, y complemente la experiencia con una visita al puente Qeshuachaka, un m&iacute;tico puente tejido a mano a&ntilde;o a a&ntilde;o por las comunidades en una tradici&oacute;n heredada de tiempos incas.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0074" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	MAGISCHE MOMENTE LUXURY	"), TRIM("	&#039;Crafting magnificent experiences in Peru, one guest at a time&#039; has been Lima Tours&rsquo; motto for the last six decades and sharing the country&rsquo;s many wonders is the passion of our entire team. We pride ourselves on offering innovative, memorable experiences, taking care of every detail when designing and managing your clients&rsquo; travels. In addition, Lima Tours has incorporated PureQuest Adventures, a specialized area created for the exclusive purpose of meeting the needs of adventure travelers who are looking for a different experience packed with adrenaline and excitement, with trips they can only take in Peru.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0075" ), 0+1);
