insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	AREQUIPA Y COLCA PROMOCIONAL	"), TRIM("	Explora Arequipa, la segunda ciudad m&aacute;s grande de Per&uacute;, durante cuatro d&iacute;as de ensue&ntilde;o. Visita su estilo colonial y sus bellas iglesias, como tambi&eacute;n las pampas que hay afuera de la ciudad con espectaculares paisajes. Admira los c&oacute;ndores del Valle del Colca y a los cam&eacute;lidos aut&oacute;ctonos de los Andes.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0078" ), 0+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	HUARAZ	"), TRIM("	Explora esta impresionante regi&oacute;n de glaciares, picos nevados y lagunas de ensue&ntilde;o durante 4 d&iacute;as de aventuras y apreciaci&oacute;n de la geograf&iacute;a e historia local. Recorre algunas de las caminatas m&aacute;s atractivas de esta parte del mundo, en las cuales descubrir&aacute;s hermosos paisajes. Disfruta de Huaraz, una joya escondida en los Andes.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0079" ), 0+1);
