insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Reserva Amazonica	"), TRIM("	Explore the jungle of Puerto Maldonado and meet its endless wildlife, either by foot through its many trails or cruising the Madre de Dios River. Discover the rich biodiversity of the Tambopata National Reserve and watch the Peruvian Amazon from the treetops through an amazing network of suspension bridges.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0006" ), 1+1);
