insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Colonial and Modern Lima	"), TRIM("	Lima is the capital of Peru, a special destination that you will discover during four wonderful days visiting its main attractions. Know its exquisite cuisine, the beautiful historic center with its squares and old residences, the Larco Museum, the districts of Miraflores and Barranco, wonderful boardwalk, and the Pachacamac archaeological complex. The group size varies but typically ranges from 6 to 10 passengers.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0019" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	ISLANDS ON LAKE TITICACA (PUNO)	"), TRIM("	Visit beautiful villages, museums, churches and temples on a journey with breathtaking sceneries between Cusco and Puno for 3 incredible days. Discover how the past is still alive in the wonderful islands of Lake Titicaca, the highest navigable lake in the world. The group size varies but typically ranges from 6 to 10 passengers.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0021" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	ARCHAEOLOGICAL TREASURES OF THE NORTH	"), TRIM("	Discover Trujillo and Chiclayo on the northern coast of Peru, during 4 days full of sunshine and culture. Visit beautiful churches and mansions from the colonial era, as well as impressive &acute;huacas&acute;, temples and archaeological sites that belonged to ancient civilizations. Wander through museums, the Chicama Valley and enjoy marine flavors offered by the Peruvian sea. Group sizes vary but typically range from 6 to 10 passengers.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0023" ), 1+1);
