insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	COLCA CANYON END PUNO	"), TRIM("	DO NOT MISS visiting the Colca Canyon which is the deepest canyon in the entire world! Be impressed by the Andean Condors that float on the rising thermals and scan for carrion far bellow them. Colca Valley has been known as &quot;The lost Valley of the Incas&quot;, &quot;The Valley of Wonders&quot;, &quot;The Valley of  fire and the territory of the Condor&quot; it is called one of the Seven Natural Wonders of the World.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0033" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	NAZCA PARACAS PACKAGE	"), TRIM("	Enjoy a wild adventure in Peru&rsquo;s remote Ica region to discover the mysterious Nazca Lines and explore the rugged Ballestas Islands. Fly over the Nazca desert and behold the geometric perfection of the ancient lines and then cruise out to the Ballestas and come face to face with their abundant fauna.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0031" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Ballestas and Nasca Lines	"), TRIM("	Discover the archaeological, cultural and natural treasures in Ica, a region south of Lima, over two exciting days. Discover the mysterious Nasca Lines from the air and the abundant fauna of the wild Ballestas Islands on a boat.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0001" ), 1+1);
