insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Rainforest Extension	"), TRIM("	This extension includes 4 nights at the reserve giving us a full 3 days for jungle walks and river trips. In the Tambopata Reserve we have selected two accommodations the Sandoval Lake Lodge or the Posadas Amazonas. You will be staying at either one of these lodges. Both are situated with good access and viewing points for exploring and have unique features for ensuring you see as much as possible of the rare wildlife of this pristine rainforest ecosystem. This extension starts and ends in Puerto Maldonaldo. The majority of flights here depart from Cusco. We can assist with these internal flights and any extra nights accommodation in Cusco or Lima that you may require.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0057" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Arequipa and the Colca Canyon	"), TRIM("	This itinerary starts with an overnight stay in the city of Arequipa, the beautiful &#039;White City&#039;, so called because many of the buildings are made from white volcanic stone. Arequipa lies in the desert mountains of the Andes and is overlooked by the impressive El Misti volcano. We have a city tour the following day which includes a visit to the famous Santa Catalina Convent, not just an interesting religious building but a fascinating 1800 square meter complex. After another night in this beautiful city we drive north to Chivay, the main town in the Colca Canyon area, where we stay overnight. We spend time exploring the area of this natural wonder - the canyon is more than twice as deep as the Grand Canyon, with more than 1 km from the cliff top to the river at the bottom! A highlight will be a visit to the Cruz Del Condor viewpoint where we are almost guaranteed to not only spot huge condors but experience them swooping over our heads as they rise out of the depths of the canyon. Following our visit to the canyon we head back to Arequipa for a final night there. This extension starts and ends in Arequipa. We can arrange flights to Arequipa from Lima, Cusco or Puno (not included).	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0058" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Lake Titicaca	"), TRIM("	We travel on the famous orient express train from Cusco to Puno, on the shores of Lake Titicaca. After an overnight in Puno we travel to the reed islands of the Uros people. Here we watch them harvesting and weaving the reeds. We overnight in a traditional village house on the islands being hosted by families. This gives us a great insight into the livelihood of these pre-Incan people. We return the following day by boat to Puno and then transfer to the nearby airport of Juliaca. This extension starts in Cusco and ends in Juliaca. Note: only available on Fridays during high season.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0059" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	LAKE TITICACA EXTENSION	"), TRIM("		"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0060" ), 1+1);
