insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	TMP PARACAS/NAZCA EXTENSION	"), TRIM("	It is estimated that the giant figures in the desert sand for which Nazca is known were begun around 400 BC and continued to be made for perhaps another thousand years. Their creators vanished without a trace, replaced by a civilisation equally advanced, which excelled in pottery, carving and metalworking. The Nazca civilisation, which peaked around 850AD, left a legacy of painted ceramics, woodcarvings, gold jewellery and wondrously painted fabrics. The Nazca Lines are a large number of geoglyphs, including several species of birds, a monkey, a spider, a fish and stylised plants, set within an enormous labyrinth of straight lines, trapezoids, triangles and spirals. These are etched into the ground as shallow, 20 centimetre-deep, channels. To compound the enigma of the site, the entire region is quite flat and desert-like, without a single point from which these ancient people could have designed the figures or admired their work. Numerous attempts have been made to explain the site, but even today the unknown outweighs the known.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0064" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	TMP PUERTO MALDONADO EXTENSION	"), TRIM("	Puerto Maldonado is an important starting point for visiting the Peruvian rainforest, although not much else happens here. A hot and sleepy place, this small jungle town sits where the Madre de Dios and Tambopata rivers meet. The town provides access to very remote jungle lodges where the spectacular flora and fauna of the rainforest can be enjoyed.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0065" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	NORTHERN CIVILISATIONS	"), TRIM("	The main reason for visiting Chiclayo is use it as a base from which to explore the spectacular Lord of Sipan Tomb, the Lord of Sipan Museum and the Pyramids of Tucume. However Chiclayo itself is a pleasant place with a friendly atmosphere, distinctive cuisine and a strong musical tradition. Peru&rsquo;s northern coast is home to some of the country&rsquo;s greatest archaeological treasures, which were built by the many highly skilled pre-Inca cultures that once thrived in the region. The elegant city of Trujillo is the main centre and this retains many old churches and graceful colonial homes built during the reign of the viceroys.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0066" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Chachapoyas Experience	"), TRIM("	Discover for five exciting days the archaeological, cultural and natural treasures of Chachapoyas, Amazon region in the Northern Jungle of Peru. Known as &#039;Warriors of the Clouds&#039;, the Chachapoyas civilization is distinguished from the Inca culture by its architecture, culture and customs. Visit the imposing Ku&eacute;lap Fortress, arriving by cable car, and get to know this little-known culture, along the Gocta waterfall.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0067" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	SKY LODGE	"), TRIM("	Experience a great adventure over two exciting days in the Sacred Valley, Southeast region of Peru. Climbing the Via Ferrata allows a vertical ascent and the Zip line is a fun and safe way to descend.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0068" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	CHACHAPOYAS EXPERIENCE	"), TRIM("	Discover for five exciting days the archaeological, cultural and natural treasures of Chachapoyas, Amazon region in the Northern Jungle of Peru. Known as &#039;Warriors of the Clouds&#039;, the Chachapoyas civilization is distinguished from the Inca culture by its architecture, culture and customs. Visit the imposing Ku&eacute;lap Fortress, arriving by cable car, and get to know this little-known culture, along with the Gocta waterfall.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0069" ), 1+1);
