insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	THE COLORS OF PALCOYO	"), TRIM("	Marvel with Palcoyo, the new mountain of colours of Cusco. Venture on a walk through the Andes discovering the beauty of this natural destination and continue the experience with a visit to the Qeshuachaka bridge. This is a mythical bridge woven by individuals of the community by hand every year in a tradition inherited from Inca times.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0074" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	MAGISHE MOMENTE LUXURY	"), TRIM("	&#039;Crafting magnificent experiences in Peru, one guest at a time&#039; has been Lima Tours&rsquo; motto for the last six decades and sharing the country&rsquo;s many wonders is the passion of our entire team. We pride ourselves on offering innovative, memorable experiences, taking care of every detail when designing and managing your clients&rsquo; travels. In addition, Lima Tours has incorporated PureQuest Adventures, a specialized area created for the exclusive purpose of meeting the needs of adventure travelers who are looking for a different experience packed with adrenaline and excitement, with trips they can only take in Peru.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0075" ), 1+1);
