insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	AREQUIPA &amp; COLCA CANYON	"), TRIM("	Explore Arequipa, the second largest city in Peru, during four awe-inspiring days. Visit its colonial-style downtown and beautiful churches, as well as the pampas outside the city, offering amazing scenery. Let the graceful flight of the condor entrance you in the Colca Valley and admire the native camelids of the Andes. Group sizes vary but usually range from minimum 1 to maximum 12 people.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0078" ), 1+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	HUARAZ	"), TRIM("	Explore this impressive region of glaciers, snow-capped peaks and dream lagoons during 4 days of adventures and appreciation of local geography and history. Walk some of the most attractive walks in this part of the world, in which you will discover beautiful landscapes. Enjoy Huaraz, a hidden gem in the Andes.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0079" ), 1+1);
