insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	EXTENSION COLCA	"), TRIM("	Esplorate Arequipa, la seconda citt&agrave; pi&ugrave; grande del Per&ugrave;. Ammirate il volo dei condor a Valle del Colca ed i camelidi originari delle Ande. Date uno sguardo al suo stile coloniale e le sue belle chiese, cos&igrave; come alle pampas che sono fuori della citt&agrave;, con uno spettacolare paesaggio	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0061" ), 3+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	ATMOSFERE PERUVIANE	"), TRIM("	Avrete l&rsquo;opportunit&agrave; di conoscere le misteriose linee di Nasca dall&#039;aria, da una barca avrete la possibilit&agrave; di ammirare l&rsquo;abbondante fauna delle selvagge Isole Ballestas in un viaggio di 5 giorni che inizia nella citt&agrave; di Arequipa e culmina nella.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0062" ), 3+1);
