insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Puno Ilhas do Titicaca	"), TRIM("	Visite formosos povoados, museus, igrejas e templos em um percurso com paisagens impressionantes entre Cusco e Puno, durante 3 incr&iacute;veis dias. Descubra como o passado continua vivo nas maravilhosas ilhas do Titicaca, o lago naveg&aacute;vel mais alto do mundo.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0002" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Trujillo &amp; Chiclayo	"), TRIM("		"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0004" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Reserva Amaz&ocirc;nica	"), TRIM("	Explore a floresta de Puerto Maldonado e conhe&ccedil;a sua intermin&aacute;vel fauna e flora, seja atrav&eacute;s de suas trilhas ou navegando pelo rio Madre de Deus. Descubra a grande biodiversidade da Reserva Nacional Tambopata e observe a Amaz&ocirc;nia peruana da copa das &aacute;rvores gra&ccedil;as a uma surpreendente rede de pontes suspensas.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0006" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Fazenda Concepci&oacute;n	"), TRIM("	Explore a floresta de Puerto Maldonado e conhe&ccedil;a sua intermin&aacute;vel fauna e flora, seja atrav&eacute;s de suas trilhas ou navegando pelo rio Madre de Deus. Descubra a grande biodiversidade da Reserva Nacional Tambopata e observe a Amaz&ocirc;nia peruana da copa das &aacute;rvores gra&ccedil;as a uma surpreendente rede de pontes suspensas. Al&eacute;m de desfruta dos mist&eacute;rios que guarda a floresta, tanto de dia como de noite realizando fascinantes excurs&otilde;es.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0008" ), 2+1);
