insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Ballestas &amp; Linhas de Nasca	"), TRIM("	Explore o Peru por ar, terra e mar durante oito emocionantes dias descobrindo os tesouros arqueol&oacute;gicos, culturais e naturais do pa&iacute;s. Conhe&ccedil;a as misteriosas linhas de Nazca do ar, descubra, dentro de um barco, a abundante fauna das selvagens Ilhas Ballestas e explore por terra as ru&iacute;nas do Imp&eacute;rio inca e as formosas cidades coloniais que foram fundadas pelos conquistadores espanh&oacute;is.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0001" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Arequipa &amp; Ca&ntilde;&oacute;n del Colca	"), TRIM("	Explore Arequipa, a segunda maior cidade do Peru, durante 4 dias de sonho. Visite seu estilo colonial e suas belas igrejas, tamb&eacute;m as pampas que existem nos arredores da cidade com espetaculares paisagens. Admire os condores do Vale do Colca e a os camel&iacute;deos aut&oacute;ctones dos Andes.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0003" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Praias do Norte	"), TRIM("	Descubra as praias do norte do Peru, durante 3 dias cheios de sol e natureza. Desfrute o avistamento de baleias jubarte em seu h&aacute;bitat natural. Relaxe contemplando o entardecer na praia enquanto desfruta de deliciosos pratos &agrave; base de produtos frescos do mar.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0005" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Reserva Amaz&ocirc;nica	"), TRIM("	Explore a floresta de Puerto Maldonado e conhe&ccedil;a sua intermin&aacute;vel fauna e flora, seja atrav&eacute;s de suas trilhas ou navegando pelo rio Madre de Deus. Descubra a grande biodiversidade da Reserva Nacional Tambopata e observe a Amaz&ocirc;nia peruana da copa das &aacute;rvores gra&ccedil;as a uma surpreendente rede de pontes suspensas.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0007" ), 2+1);
