insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	EXPERI&Ecirc;NCIA DE CHACHAPOYAS	"), TRIM("	Descubra por cinco dias emocionantes os tesouros arqueol&oacute;gicos, culturais e naturais de Chachapoyas, regi&atilde;o amaz&ocirc;nica na selva do norte do Peru. Conhecido como &quot;Guerreiros das Nuvens&quot;, a civiliza&ccedil;&atilde;o Chachapoyas se distingue da cultura Inca pela arquitetura, cultura e costumes. Visite a imponente Fortaleza Ku&eacute;lap com telef&eacute;rico para conhecer esta cultura pouco conhecida, juntamente com a cachoeira Gocta.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0067" ), 2+1);
insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Sky Lodge	"), TRIM("	Aproveite durante dois dias emocionantes a aventura no Vale Sagrado, regi&atilde;o sudeste do Peru. A escalada da Via Ferrata permite uma experi&ecirc;ncia vertical e a linha Zip uma maneira divertida e segura de descer.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0068" ), 2+1);
