insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	Palcoyo Multicolorido	"), TRIM("	Maravilhe-se com o Palcoyo, a nova montanha de cores de Cusco. Aventure-se em um passeio pelos Andes descobrindo a beleza deste destino natural, e complemente a experi&ecirc;ncia com uma visita &agrave; ponte Qeshuachaka, uma ponte m&iacute;tica tecida &agrave; m&atilde;o todos os anos pelas comunidades em uma tradi&ccedil;&atilde;o herdada dos tempos incas.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0074" ), 2+1);
