insert into package_translations ( name, description, label, itinerary_link, itinerary_label, itinerary_description, package_id, language_id )values( TRIM("	AREQUIPA &amp; C&Acirc;NION DO COLCA	"), TRIM("	Explore Arequipa, a segunda maior cidade do Peru, durante 4 dias de sonho. Visite seu estilo colonial e suas belas igrejas, tamb&eacute;m as pampas que existem nos arredores da cidade com espetaculares paisagens. Admire os condores do Vale do Colca e a os camel&iacute;deos aut&oacute;ctones dos Andes. O tamanho dos grupos &eacute; vari&aacute;vel, mas em geral s&atilde;o compostos por 6 a 10 passageiros.	"), "",TRIM("		"), TRIM("		"), TRIM("		"), 	(select id from packages where code = "EX0078" ), 2+1);
